import React, { useEffect, useRef, useState } from 'react';
import * as d3 from 'd3';

function SentimentChart({ range }) {
    const d3Container = useRef(null);
    const [isLoading, setIsLoading] = useState(false);

    // 模擬情緒數據生成器
    const generateMockSentimentData = () => {
        const data = [];
        const startDate = new Date(2020, 0, 1);
        const endDate = new Date(2024, 11, 31);
        const days = Math.floor((endDate - startDate) / (1000 * 60 * 60 * 24));

        for (let i = 0; i < days; i += 7) { // 每週一個數據點
            const date = new Date(startDate.getTime() + i * 24 * 60 * 60 * 1000);

            // 生成基於正弦波的情緒數據，模擬週期性變化
            const trend = Math.sin(i / 100) * 0.3;
            const noise = (Math.random() - 0.5) * 0.4;
            const sentimentScore = Math.max(-1, Math.min(1, trend + noise));

            // 計算正面、中性、負面比例
            const positive = sentimentScore > 0 ? 0.3 + sentimentScore * 0.4 : 0.2;
            const negative = sentimentScore < 0 ? 0.3 + Math.abs(sentimentScore) * 0.4 : 0.2;
            const neutral = 1 - positive - negative;

            data.push({
                date,
                sentimentScore,
                positive: positive * 100,
                neutral: neutral * 100,
                negative: negative * 100,
                volume: Math.floor(Math.random() * 10000) + 5000, // 社群活躍度
                fearGreed: Math.floor((sentimentScore + 1) * 50), // 0-100
                keywords: ['bitcoin', 'crypto', 'blockchain', 'hodl', 'moon'].slice(0, Math.floor(Math.random() * 3) + 2)
            });
        }

        return data;
    };

    useEffect(() => {
        if (!d3Container.current) return;

        setIsLoading(true);

        // 模擬API請求延遲
        setTimeout(() => {
            let data = generateMockSentimentData();

            // 如果有範圍選擇，應用範圍過濾
            if (range && range.length === 2) {
                const totalDays = data.length;
                const startIdx = Math.floor((range[0] / totalDays) * data.length);
                const endIdx = Math.floor((range[1] / totalDays) * data.length);
                data = data.slice(startIdx, endIdx + 1);
            }

            drawChart(data);
            setIsLoading(false);
        }, 500);

    }, [range]);

    const drawChart = (data) => {
        if (!data.length) return;

        const container = d3Container.current;
        const containerRect = container.getBoundingClientRect();
        const width = containerRect.width;
        const height = 400;
        const margin = { top: 20, right: 60, bottom: 60, left: 60 };

        // 清除之前的圖表
        d3.select(container).selectAll('*').remove();

        const svg = d3.select(container)
            .append('svg')
            .attr('width', width)
            .attr('height', height)
            .style('background', 'linear-gradient(135deg, #1e1e3f 0%, #2a2a5a 100%)');

        // 時間和情緒分數比例尺
        const xScale = d3.scaleTime()
            .domain(d3.extent(data, d => d.date))
            .range([margin.left, width - margin.right]);

        const yScale = d3.scaleLinear()
            .domain([-1, 1])
            .range([height - margin.bottom, margin.top]);

        const volumeScale = d3.scaleLinear()
            .domain([0, d3.max(data, d => d.volume)])
            .range([0, 30]);

        // 創建主要區域
        const mainGroup = svg.append('g');

        // 背景網格
        const xAxis = d3.axisBottom(xScale).ticks(6);
        const yAxis = d3.axisLeft(yScale).ticks(5);

        // Y軸
        mainGroup.append('g')
            .attr('transform', `translate(${margin.left},0)`)
            .call(yAxis)
            .call(g => g.selectAll('text').attr('fill', '#ffffff'))
            .call(g => g.selectAll('line').attr('stroke', 'rgba(255,255,255,0.2)'));

        // X軸
        mainGroup.append('g')
            .attr('transform', `translate(0,${height - margin.bottom})`)
            .call(xAxis)
            .call(g => g.selectAll('text').attr('fill', '#ffffff'))
            .call(g => g.selectAll('line').attr('stroke', 'rgba(255,255,255,0.2)'));

        // 零線
        mainGroup.append('line')
            .attr('x1', margin.left)
            .attr('x2', width - margin.right)
            .attr('y1', yScale(0))
            .attr('y2', yScale(0))
            .attr('stroke', 'rgba(255,255,255,0.5)')
            .attr('stroke-width', 1)
            .attr('stroke-dasharray', '5,5');

        // 情緒分數面積圖
        const area = d3.area()
            .x(d => xScale(d.date))
            .y0(yScale(0))
            .y1(d => yScale(d.sentimentScore))
            .curve(d3.curveCardinal);

        const areaPath = mainGroup.append('path')
            .datum(data)
            .attr('d', area)
            .attr('fill', 'url(#sentimentGradient)')
            .attr('opacity', 0.6);

        // 情緒分數線
        const line = d3.line()
            .x(d => xScale(d.date))
            .y(d => yScale(d.sentimentScore))
            .curve(d3.curveCardinal);

        mainGroup.append('path')
            .datum(data)
            .attr('d', line)
            .attr('fill', 'none')
            .attr('stroke', '#4ade80')
            .attr('stroke-width', 3)
            .attr('filter', 'drop-shadow(0 0 6px rgba(74, 222, 128, 0.6))');

        // 社群活躍度氣泡
        mainGroup.selectAll('.volume-bubble')
            .data(data.filter((d, i) => i % 4 === 0)) // 每4個點顯示一個氣泡
            .enter()
            .append('circle')
            .attr('class', 'volume-bubble')
            .attr('cx', d => xScale(d.date))
            .attr('cy', d => yScale(d.sentimentScore))
            .attr('r', d => volumeScale(d.volume) / 3)
            .attr('fill', 'rgba(59, 130, 246, 0.4)')
            .attr('stroke', '#3b82f6')
            .attr('stroke-width', 1);

        // 漸變定義
        const defs = svg.append('defs');
        const gradient = defs.append('linearGradient')
            .attr('id', 'sentimentGradient')
            .attr('gradientUnits', 'userSpaceOnUse')
            .attr('x1', 0).attr('y1', yScale(1))
            .attr('x2', 0).attr('y2', yScale(-1));

        gradient.append('stop')
            .attr('offset', '0%')
            .attr('stop-color', '#10b981')
            .attr('stop-opacity', 0.8);

        gradient.append('stop')
            .attr('offset', '50%')
            .attr('stop-color', '#f59e0b')
            .attr('stop-opacity', 0.4);

        gradient.append('stop')
            .attr('offset', '100%')
            .attr('stop-color', '#ef4444')
            .attr('stop-opacity', 0.8);

        // 圖例
        const legend = svg.append('g')
            .attr('transform', `translate(${width - margin.right + 10}, ${margin.top})`);

        const legendData = [
            { color: '#10b981', label: '正面情緒', value: '+1.0' },
            { color: '#f59e0b', label: '中性情緒', value: '0.0' },
            { color: '#ef4444', label: '負面情緒', value: '-1.0' },
            { color: '#3b82f6', label: '活躍度', value: 'Vol' }
        ];

        const legendItems = legend.selectAll('.legend-item')
            .data(legendData)
            .enter()
            .append('g')
            .attr('class', 'legend-item')
            .attr('transform', (d, i) => `translate(0, ${i * 25})`);

        legendItems.append('circle')
            .attr('r', 6)
            .attr('fill', d => d.color);

        legendItems.append('text')
            .attr('x', 15)
            .attr('y', 0)
            .attr('dy', '0.35em')
            .attr('fill', '#ffffff')
            .attr('font-size', '12px')
            .text(d => d.label);

        legendItems.append('text')
            .attr('x', 15)
            .attr('y', 12)
            .attr('dy', '0.35em')
            .attr('fill', 'rgba(255,255,255,0.6)')
            .attr('font-size', '10px')
            .text(d => d.value);

        // 標題和標籤
        svg.append('text')
            .attr('x', width / 2)
            .attr('y', margin.top / 2)
            .attr('text-anchor', 'middle')
            .attr('fill', '#ffffff')
            .attr('font-size', '16px')
            .attr('font-weight', 'bold')
            .text('社群情緒趨勢分析');

        svg.append('text')
            .attr('transform', 'rotate(-90)')
            .attr('x', -height / 2)
            .attr('y', 20)
            .attr('text-anchor', 'middle')
            .attr('fill', 'rgba(255,255,255,0.8)')
            .attr('font-size', '12px')
            .text('情緒分數');

        svg.append('text')
            .attr('x', width / 2)
            .attr('y', height - 10)
            .attr('text-anchor', 'middle')
            .attr('fill', 'rgba(255,255,255,0.8)')
            .attr('font-size', '12px')
            .text('時間');

        // 互動提示
        const tooltip = d3.select('body')
            .append('div')
            .attr('class', 'sentiment-tooltip')
            .style('position', 'absolute')
            .style('visibility', 'hidden')
            .style('background', 'rgba(0, 0, 0, 0.9)')
            .style('color', 'white')
            .style('padding', '10px')
            .style('border-radius', '8px')
            .style('font-size', '12px')
            .style('pointer-events', 'none')
            .style('z-index', '1000');

        // 互動點
        mainGroup.selectAll('.sentiment-point')
            .data(data.filter((d, i) => i % 2 === 0))
            .enter()
            .append('circle')
            .attr('class', 'sentiment-point')
            .attr('cx', d => xScale(d.date))
            .attr('cy', d => yScale(d.sentimentScore))
            .attr('r', 4)
            .attr('fill', d => d.sentimentScore > 0 ? '#10b981' : d.sentimentScore < 0 ? '#ef4444' : '#f59e0b')
            .attr('stroke', '#ffffff')
            .attr('stroke-width', 2)
            .attr('opacity', 0.8)
            .style('cursor', 'pointer')
            .on('mouseover', function (event, d) {
                d3.select(this).attr('r', 6);
                tooltip.style('visibility', 'visible')
                    .html(`
                        <strong>${d3.timeFormat('%Y-%m-%d')(d.date)}</strong><br/>
                        情緒分數: ${d.sentimentScore.toFixed(3)}<br/>
                        正面: ${d.positive.toFixed(1)}%<br/>
                        中性: ${d.neutral.toFixed(1)}%<br/>
                        負面: ${d.negative.toFixed(1)}%<br/>
                        活躍度: ${d.volume.toLocaleString()}<br/>
                        恐懼貪婪: ${d.fearGreed}
                    `);
            })
            .on('mousemove', function (event) {
                tooltip.style('top', (event.pageY - 10) + 'px')
                    .style('left', (event.pageX + 10) + 'px');
            })
            .on('mouseout', function () {
                d3.select(this).attr('r', 4);
                tooltip.style('visibility', 'hidden');
            });
    };

    return (
        <div style={{ width: '100%', height: '400px', position: 'relative' }}>
            {isLoading && (
                <div style={{
                    position: 'absolute',
                    top: '50%',
                    left: '50%',
                    transform: 'translate(-50%, -50%)',
                    color: '#ffffff',
                    fontSize: '1.1rem',
                    zIndex: 10
                }}>
                    <div style={{
                        width: '40px',
                        height: '40px',
                        border: '4px solid rgba(255,255,255,0.3)',
                        borderTop: '4px solid #4ade80',
                        borderRadius: '50%',
                        animation: 'spin 1s linear infinite',
                        margin: '0 auto 1rem'
                    }}></div>
                    載入情緒數據中...
                </div>
            )}
            <div
                ref={d3Container}
                style={{
                    width: '100%',
                    height: '100%',
                    opacity: isLoading ? 0.3 : 1,
                    transition: 'opacity 0.3s ease'
                }}
            />
            <style jsx>{`
                @keyframes spin {
                    0% { transform: rotate(0deg); }
                    100% { transform: rotate(360deg); }
                }
            `}</style>
        </div>
    );
}

export default SentimentChart;
